import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { authAPI, notificationAPI } from '../services/api';
import CartIcon from './CartIcon';
import WishlistIcon from './WishlistIcon';   // ✅ NEW
import './Navbar.css';

export default function Navbar() {
  const { user, isLoggedIn, isAdmin, logout } = useAuth();
  const toast    = useToast();
  const navigate = useNavigate();
  const location = useLocation();
  const [menuOpen,    setMenuOpen]    = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const pollRef = useRef(null);

  // ── Poll unread notification count every 30 seconds ──────────────────────
  useEffect(() => {
    if (!isLoggedIn() || isAdmin()) {
      setUnreadCount(0);
      return;
    }

    const fetchCount = async () => {
      try {
        const res = await notificationAPI.getUnreadCount();
        setUnreadCount(res.data?.unreadCount ?? 0);
      } catch {
        // silently ignore — don't disrupt the UI
      }
    };

    fetchCount();
    pollRef.current = setInterval(fetchCount, 30_000);
    return () => clearInterval(pollRef.current);
  }, [isLoggedIn, isAdmin, location.pathname]);

  const handleLogout = async () => {
    try { await authAPI.logout(); } catch {}
    logout();
    toast.success('Logged out successfully');
    navigate('/');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="navbar">
      <div className="container navbar-inner">

        {/* Logo */}
        <Link to="/" className="navbar-logo">
          <span className="logo-icon">📚</span>
          <span className="logo-text">Book<em>Nest</em></span>
        </Link>

        {/* Desktop nav links */}
        <div className="navbar-links">
          <Link to="/books" className={`nav-link ${isActive('/books') ? 'active' : ''}`}>
            Catalog
          </Link>
          {isLoggedIn() && !isAdmin() && (
            <Link to="/orders" className={`nav-link ${isActive('/orders') ? 'active' : ''}`}>
              My Orders
            </Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/my-reviews" className={`nav-link ${isActive('/my-reviews') ? 'active' : ''}`}>
              ⭐ My Reviews
            </Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/wallet" className={`nav-link ${isActive('/wallet') ? 'active' : ''}`}>
              💰 Wallet
            </Link>
          )}
          {isLoggedIn() && (
            <Link to="/dashboard" className={`nav-link ${isActive('/dashboard') ? 'active' : ''}`}>
              {isAdmin() ? 'Admin Panel' : 'Dashboard'}
            </Link>
          )}
        </div>

        {/* Desktop actions: Wishlist + Cart + Bell + User + Logout */}
        <div className="navbar-actions">
          {/* ✅ Wishlist icon — customers only */}
          {isLoggedIn() && !isAdmin() && <WishlistIcon />}

          {isLoggedIn() && !isAdmin() && <CartIcon />}

          {/* Notification Bell — customers only */}
          {isLoggedIn() && !isAdmin() && (
            <Link
              to="/notifications"
              className="notif-bell-link"
              title="Notifications"
              onClick={() => setUnreadCount(0)}
            >
              🔔
              {unreadCount > 0 && (
                <span className="notif-bell-badge">
                  {unreadCount > 99 ? '99+' : unreadCount}
                </span>
              )}
            </Link>
          )}

          {isLoggedIn() ? (
            <>
              <span className="nav-user">
                👤 {user?.fullName || user?.email?.split('@')[0] || 'User'}
                {isAdmin() && (
                  <span className="badge badge-gold" style={{ marginLeft: 6 }}>Admin</span>
                )}
              </span>
              <button className="btn btn-ghost btn-sm" onClick={handleLogout}>
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login"    className="btn btn-ghost btn-sm">Login</Link>
              <Link to="/register" className="btn btn-gold  btn-sm">Register</Link>
            </>
          )}
        </div>

        {/* Mobile hamburger */}
        <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen ? '✕' : '☰'}
        </button>
      </div>

      {/* Mobile dropdown menu */}
      {menuOpen && (
        <div className="mobile-menu fade-in">
          <Link to="/books" onClick={() => setMenuOpen(false)}>Catalog</Link>

          {isLoggedIn() && !isAdmin() && (
            <Link to="/cart" onClick={() => setMenuOpen(false)}>🛒 Cart</Link>
          )}
          {/* ✅ Wishlist link in mobile menu */}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/wishlist" onClick={() => setMenuOpen(false)}>💝 My Wishlist</Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/orders" onClick={() => setMenuOpen(false)}>📦 My Orders</Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/my-reviews" onClick={() => setMenuOpen(false)}>⭐ My Reviews</Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link to="/wallet" onClick={() => setMenuOpen(false)}>💰 Wallet</Link>
          )}
          {isLoggedIn() && !isAdmin() && (
            <Link
              to="/notifications"
              onClick={() => { setMenuOpen(false); setUnreadCount(0); }}
            >
              🔔 Notifications{unreadCount > 0 ? ` (${unreadCount})` : ''}
            </Link>
          )}
          {isLoggedIn() && (
            <Link to="/dashboard" onClick={() => setMenuOpen(false)}>
              {isAdmin() ? 'Admin Panel' : 'Dashboard'}
            </Link>
          )}

          {isLoggedIn() ? (
            <button onClick={() => { handleLogout(); setMenuOpen(false); }}>
              Logout
            </button>
          ) : (
            <>
              <Link to="/login"    onClick={() => setMenuOpen(false)}>Login</Link>
              <Link to="/register" onClick={() => setMenuOpen(false)}>Register</Link>
            </>
          )}
        </div>
      )}
    </nav>
  );
}
